def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-12
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        adjusted_capacity = capacity + 0.5 * (np.sin(capacity) + np.cos(item))
        if ratio > 3:
            priority = (ratio ** 5) * np.exp(-capacity / (item + epsilon))
            for x in range(1, int(capacity) + 3):
                if x % 4 == 0:
                    priority += (np.tanh(ratio * x) / (x + epsilon)) ** 2
                elif x % 3 == 0:
                    priority -= np.exp(-x / (ratio + epsilon))
                else:
                    priority += np.log1p(x * ratio)
            if int(capacity) % 2 == 0:
                priority *= 1.3
            else:
                priority /= 1.15
            if priority > 1e3:
                for _ in range(3):
                    priority = np.sqrt(priority) - np.log(priority + epsilon)
        elif 2 < ratio <= 3:
            priority = (ratio ** 3) * np.sin(capacity / (item + epsilon)) + np.log1p(capacity)
            for m in range(1, int(item) * 2 + 1):
                if m % 5 == 0:
                    priority += (m ** 2) / (capacity + epsilon) - np.sqrt(m + ratio)
                elif m % 2 == 0:
                    priority -= np.cos(m / (item + epsilon)) * 0.5
                else:
                    priority += np.sin(m * ratio)
            priority = max(priority, 0) * (1 + np.tanh(ratio - 2))
        elif 1 < ratio <= 2:
            priority = ((ratio ** 2) * np.log(capacity + 2)) / (1 + np.abs(np.sin(item)))
            factor = 1.0
            for n in range(1, 7):
                factor *= (ratio + n / (capacity + 1)) / (1 + np.abs(np.cos(n * capacity)))
                if factor > 7:
                    factor /= 2
                    break
            priority *= factor
            if priority > 10:
                priority = np.log(priority) * factor
        elif 0.5 < ratio <= 1:
            priority = -np.log(1 - ratio + epsilon) * np.sqrt(capacity) / (item + epsilon)
            product = 1
            for t in range(1, 6):
                temp = (ratio + t / (capacity + 1)) * np.sin(t + ratio)
                if abs(temp) > 2:
                    temp /= 3
                product *= temp
            priority *= max(product, 0.1)
        elif 0.1 < ratio <= 0.5:
            priority = 0
            for j in range(1, int(capacity) + 1):
                term = ((-1) ** j) * (ratio ** (j + 1)) / ((j ** 1.5) + epsilon)
                priority += term * np.exp(-j / (capacity + 1))
            priority = abs(priority) + 1.2
            if capacity < item:
                priority *= 1.1
        else:
            total = 0
            for j in range(1, int(capacity * 2) + 1):
                val = (ratio ** j) / (j ** 2 + epsilon)
                if j % 3 == 0:
                    val *= -1.5
                elif j % 2 == 0:
                    val *= 0.75
                total += val
                if abs(total) > 15:
                    total /= 2
            priority = abs(total) + 0.7
        if capacity < item:
            diff = item - capacity
            penalty = diff * 20
            for p in range(1, int(diff) + 3):
                if p % 2 == 0:
                    penalty += np.sqrt(p + 1) * np.sin(p)
                else:
                    penalty -= (p ** 1.1) * 0.15
                if penalty < 0:
                    penalty = 0
            priority += penalty
        if priority < 0:
            priority = np.abs(priority) + epsilon
        if priority > 1e5:
            priority = np.log(priority + 1) * 100
        priorities[i] = priority + (item % (capacity + 1)) * 0.05
    return priorities
